const formatCurrency = (value: number) => {
    return `SAR ${Math.round(value).toLocaleString('en-US')}`;
};

type CaseType = 'worst' | 'base' | 'best';

// --- Apple-Style Segmented Control (Unified White Pill Design) ---
const SegmentedControl: React.FC<{
    options: { value: string | number; label: string }[];
    selected: string | number;
    onChange: (value: any) => void;
    dark?: boolean;
}> = ({ options, selected, onChange, dark = false }) => {

    // Unified Design: Always White Pill for Selection
    // Light Mode: Gray Container, White Pill
    // Dark Mode: Translucent White Container, White Pill

    const containerClass = dark ? 'bg-white/10' : 'bg-gray-100';
    const activePillClass = 'bg-white shadow-sm ring-1 ring-black/5';

    // Text Colors
    const activeTextClass = 'text-gray-900'; // Always dark text on white pill
    const inactiveTextClass = dark ? 'text-white/70 hover:text-white' : 'text-gray-500 hover:text-gray-900';

    return (
        <div className={`p-1 rounded-full flex relative w-full sm:w-auto overflow-hidden ${containerClass}`}>
            {options.map((option) => {
                const isActive = selected === option.value;
                return (
                    <button
                        key={option.value}
                        onClick={() => onChange(option.value)}
                        className={`relative z-10 flex-1 px-4 py-1.5 text-xs sm:text-sm font-bold transition-colors duration-200 rounded-full whitespace-nowrap ${
                            isActive ? activeTextClass : inactiveTextClass
                        }`}
                        style={{ WebkitTapHighlightColor: 'transparent' }}
                    >
                        {isActive && (
                            <motion.div
                                layoutId={dark ? "activeSegmentDark" : "activeSegmentLight"}
                                className={`absolute inset-0 rounded-full ${activePillClass}`}
                                transition={{ type: "spring", stiffness: 300, damping: 30 }}
                            />
                        )}
                        <span className="relative z-10">{option.label}</span>
                    </button>
                );
            })}
        </div>
    );
};

