  // Mathwaa Share and Net Income based on toggle
  const effectiveMathwaa = Math.round(effectiveRevenue * mathwaaPercentage);
  const effectiveNetIncome = effectiveRevenue - effectiveMathwaa;

  const effectiveROI = ((effectiveNetIncome / activeScenario.propertyValue) * 100).toFixed(2);

