const App_en: React.FC<{ onToggleLanguage: () => void }> = ({ onToggleLanguage }) => {
  const [activeScenarioId, setActiveScenarioId] = useState<string>(SCENARIOS[0].id);
  const [activeCase, setActiveCase] = useState<CaseType>('base');
  const [occupancyRate, setOccupancyRate] = useState<number>(1); // 1 = 100%
  const [mathwaaPercentage, setMathwaaPercentage] = useState<number>(0.30); // Default to 30%

  const activeScenario = SCENARIOS.find(s => s.id === activeScenarioId) || SCENARIOS[0];
  const baseFinancials = activeScenario.financials[activeCase];

  // Dynamic Calculations
  const effectiveRevenue = Math.round(baseFinancials.revenue * occupancyRate);

  // STR Specifics: OTA Fee (15.5%)
  // Hybrid Specifics: OTA Fee on ~45% of revenue
  const isSTR = activeScenarioId === 'short_term';
  const isHybrid = activeScenarioId === 'hybrid';

  // Determine share of revenue subject to OTA fees
  // STR = 100% of revenue, Hybrid = ~45% (Dec-Mar peak), LTR = 0%
  const revenueShareSubjectToOta = isSTR ? 1.0 : (isHybrid ? 0.45 : 0);
  const otaFeePercentage = 0.155; // 15.5%

  // 1. Calculate OTA Fee based on Revenue Share
  const effectiveOtaFee = Math.round(effectiveRevenue * revenueShareSubjectToOta * otaFeePercentage);

  // 2. Mathwaa Share is calculated on the NET REVENUE (Gross - OTA)
  const netRevenueAfterOta = effectiveRevenue - effectiveOtaFee;
  const effectiveMathwaa = Math.round(netRevenueAfterOta * mathwaaPercentage);

  // 3. Owner Net Income
  const effectiveNetIncome = netRevenueAfterOta - effectiveMathwaa;

  // Recalculate ROI dynamically
  const effectiveROI = ((effectiveNetIncome / activeScenario.propertyValue) * 100).toFixed(2);


