  ] : [
      { value: 'worst', label: 'Conservative' },
      { value: 'base', label: 'Realistic' },
      { value: 'best', label: 'Optimistic' },
  ];

  const allOccupancyOptions = [
      { value: 0.4, label: '40%' },
      { value: 0.5, label: '50%' },
      { value: 0.6, label: '60%' },
      { value: 0.7, label: '70%' },
