  const translateDuration = (label: string) => {
      if (label === '12 Months LTR (Adj.)') return 'تأجير سنوي ١٢ شهر'; // Removed "Adj." for dynamic view
      if (label === 'Daily Rentals') return 'تأجير يومي';
      return 'يومي + سنوي';
