      { value: 'worst', label: 'متحفظ' },
      { value: 'base', label: 'واقعي' },
      { value: 'best', label: 'متفائل' },
  ];

  const allOccupancyOptions = [
      { value: 0.4, label: '٤٠٪' },
      { value: 0.5, label: '٥٠٪' },
      { value: 0.6, label: '٦٠٪' },
      { value: 0.7, label: '٧٠٪' },
      { value: 0.8, label: '٨٠٪' },
