      ledgerItems.push({ category: `رسوم منصات الحجز (${percentageLabel})`, amount: effectiveOtaFee, color: 'bg-blue-400' });
  }

  ledgerItems.push({ category: `حصة مثوى (${Math.round(mathwaaPercentage * 100)}٪ من الصافي)`, amount: effectiveMathwaa, color: 'bg-purple-400' });
