            </div>

            <FadeInUp>
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 sm:gap-6 text-right">

                     {/* Winner Card */}
                     <div className="lg:col-span-5 bg-white rounded-2xl sm:rounded-[1.5rem] p-6 sm:p-8 shadow-[0_4px_20px_rgba(0,0,0,0.03)] border border-gray-100 flex flex-col justify-center relative overflow-hidden group hover:shadow-[0_30px_60px_rgba(0,0,0,0.08)] transition-shadow duration-500">
