            name: 'الإيرادات', 
            Hybrid: SCENARIOS[0].financials[activeCase].revenue, 
            STR: SCENARIOS[1].financials[activeCase].revenue,
            LTR: SCENARIOS[2].financials[activeCase].revenue 
        },
        { 
            name: 'صافي الدخل', 
            Hybrid: SCENARIOS[0].financials[activeCase].netIncome, 
            STR: SCENARIOS[1].financials[activeCase].netIncome,
            LTR: SCENARIOS[2].financials[activeCase].netIncome 
