                                 <h4 className="text-white font-bold text-base sm:text-lg mb-2">الاستراتيجية</h4>
                                 <p className="text-sm text-white/60 leading-relaxed font-light">
                                     {translateScenarioDesc(activeScenario.id)}
                                 </p>
                             </div>

                        </div>

                    </motion.div>
                </AnimatePresence>
            </div>
        </Section>

      </main>
    </div>
  );
