  if (effectiveOtaFee > 0) {
      ledgerItems.push({ category: `OTA Fees (15.5%)`, amount: effectiveOtaFee, color: 'bg-blue-400' });
  }

  // Calculate percentage of GROSS revenue for display
  const mathwaaDisplayPercent = Math.round((effectiveMathwaa / effectiveRevenue) * 100);

  ledgerItems.push({ category: `Mathwaa Share (${Math.round(mathwaaPercentage * 100)}% of Net)`, amount: effectiveMathwaa, color: 'bg-purple-400' });
  ledgerItems.push({ category: 'Net Income (Owner)', amount: effectiveNetIncome, color: 'bg-emerald-400', highlight: true });


  return (
    <div className="min-h-screen bg-[#F5F5F7] text-[#1D1D1F] font-sans overflow-x-hidden selection:bg-[#4A2C5A] selection:text-white">
      <Header onToggleLanguage={onToggleLanguage} />

