export const OccupancyRadial: React.FC<{
  percentage: number;
  label: string;
  subLabel: string;
  color: string;
}> = ({ percentage, label, subLabel, color }) => {
  const radius = 45;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (percentage / 100) * circumference;

  return (
    <div className="bg-white/40 backdrop-blur-xl border border-white/50 p-6 sm:p-8 rounded-[2rem] shadow-lg flex flex-col items-center justify-center text-center h-full transition-all duration-500 hover:scale-105 hover:shadow-2xl">
      <h3 className="text-lg font-bold text-[#003846] mb-6 sm:mb-8">{label}</h3>
      <div className="relative w-32 h-32 sm:w-40 sm:h-40 flex items-center justify-center mb-6 sm:mb-8">
        <svg className="w-full h-full transform -rotate-90" viewBox="0 0 120 120">
          <circle
            cx="60"
            cy="60"
            r={radius}
            fill="none"
            stroke="#e5e7eb"
            strokeWidth="6"
            strokeLinecap="round"
          />
          <circle
            cx="60"
            cy="60"
            r={radius}
            fill="none"
            stroke={color}
            strokeWidth="6"
            strokeDasharray={circumference}
            strokeDashoffset={strokeDashoffset}
            strokeLinecap="round"
            className="transition-all duration-1500 ease-out"
          />
        </svg>
        <div className="absolute flex flex-col items-center">
            <span className="text-3xl sm:text-4xl font-extrabold text-[#003846] tracking-tight">{percentage}%</span>
        </div>
      </div>
      <p className="text-sm font-medium text-[#003846]/60 px-2 sm:px-4">{subLabel}</p>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import type { Branch, NewBooking } from '../types';

interface AddBookingModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (booking: NewBooking) => void;
  branches: Branch[];
}

const AddBookingModal: React.FC<AddBookingModalProps> = ({ isOpen, onClose, onSubmit, branches }) => {
  const [branchId, setBranchId] = useState(branches[0]?.id || '');
  const [apartmentId, setApartmentId] = useState('');
  const [contractDurationMonths, setContractDurationMonths] = useState(12);
  const [howHeard, setHowHeard] = useState('');

  const vacantApartments = branches.find(b => b.id === branchId)?.apartments.filter(a => a.status === 'VACANT') || [];

  useEffect(() => {
    // Reset apartment selection when branch changes
    setApartmentId(vacantApartments[0]?.id || '');
  }, [branchId, branches]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!branchId || !apartmentId || !contractDurationMonths || !howHeard) {
      alert('Please fill all fields.');
      return;
    }
    onSubmit({
      branchId,
      apartmentId,
      contractDurationMonths: Number(contractDurationMonths),
      howHeard,
    });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-[#F9F7F5] rounded-2xl shadow-xl w-full max-w-lg p-8 m-4" onClick={e => e.stopPropagation()}>
        <h2 className="text-2xl font-bold text-[#003846] mb-6">Add New Booking</h2>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label htmlFor="branch" className="block text-sm font-medium text-[#003846]/80">Branch</label>
            <select
              id="branch"
              value={branchId}
              onChange={e => setBranchId(e.target.value)}
              className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300/50 focus:outline-none focus:ring-[#88C9C9] focus:border-[#88C9C9] sm:text-sm rounded-md bg-white/80"
            >
              {branches.map(branch => (
                <option key={branch.id} value={branch.id}>{branch.name}</option>
              ))}
            </select>
          </div>

          <div>
            <label htmlFor="apartment" className="block text-sm font-medium text-[#003846]/80">Vacant Apartment</label>
            <select
              id="apartment"
              value={apartmentId}
              onChange={e => setApartmentId(e.target.value)}
              disabled={vacantApartments.length === 0}
              className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300/50 focus:outline-none focus:ring-[#88C9C9] focus:border-[#88C9C9] sm:text-sm rounded-md bg-white/80"
            >
              {vacantApartments.length > 0 ? vacantApartments.map(apt => (
                <option key={apt.id} value={apt.id}>
                  Apt #{apt.number} ({apt.type} - SAR {apt.monthlyRent}/mo)
                </option>
              )) : <option>No vacant apartments in this branch</option>}
            </select>
          </div>

          <div>
            <label htmlFor="duration" className="block text-sm font-medium text-[#003846]/80">Contract Duration (Months)</label>
            <input
              type="number"
              id="duration"
              min="1"
              value={contractDurationMonths}
              onChange={e => setContractDurationMonths(Number(e.target.value))}
              className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300/50 focus:outline-none focus:ring-[#88C9C9] focus:border-[#88C9C9] sm:text-sm rounded-md bg-white/80"
            />
          </div>

           <div>
            <label htmlFor="source" className="block text-sm font-medium text-[#003846]/80">Acquisition Source (e.g., Bayut, Facebook Ad)</label>
            <input
              type="text"
              id="source"
              value={howHeard}
              onChange={e => setHowHeard(e.target.value)}
              placeholder="How did the tenant hear about us?"
              className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300/50 focus:outline-none focus:ring-[#88C9C9] focus:border-[#88C9C9] sm:text-sm rounded-md bg-white/80"
            />
          </div>

          <div className="flex justify-end gap-4 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="px-6 py-2 text-sm font-semibold text-[#003846] bg-gray-500/20 rounded-md hover:bg-gray-500/30 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              className="px-6 py-2 text-sm font-semibold text-white bg-[#003846] rounded-md hover:bg-opacity-90 transition-colors"
            >
              Add Booking
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

