            </div>
            <h1 className="text-5xl sm:text-7xl font-black text-[#003846] tracking-tighter mb-4 sm:mb-6 leading-[0.9]">
              مشروع النزهة<span className="text-[#88C9C9]">.</span>
            </h1>
            <p className="text-lg sm:text-2xl text-[#003846]/60 max-w-3xl mx-auto font-medium leading-relaxed tracking-tight px-4">
                تقييم الاستخدام الأمثل لمجمع الـ ٩ وحدات: <span className="text-[#003846]">هجين</span>, <span className="text-[#D4AF37]">يومي</span> و <span className="text-[#88C9C9]">سنوي</span>.
            </p>
          </div>
        </FadeInUp>

        {/* Section 2: Interactive Deep Dive */}
        <Section title="تحليل تفاعلي" className="!mt-0 !pt-0" titleColor="text-[#003846]">

            <div className="bg-[#003846] text-white rounded-3xl sm:rounded-[2rem] shadow-2xl relative overflow-hidden ring-1 ring-white/10">
                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 mix-blend-overlay pointer-events-none"></div>

                <div className="bg-white/5 backdrop-blur-xl border-b border-white/5 p-4 sm:p-6 flex flex-col gap-4 sticky top-0 z-20">
