                        {/* LEFT COLUMN (Context - RTL) */}
                        <div className="lg:col-span-5 space-y-6 lg:order-1">

                             <div className="bg-white/5 p-6 sm:p-8 rounded-2xl sm:rounded-[1.5rem] border border-white/10">
